import logging
import logging.handlers
import os
from pathlib import Path

# Create log directory if it doesn't exist
LOG_DIR = Path('/var/log/application')
LOG_DIR.mkdir(parents=True, exist_ok=True)

# Define log file paths
MAIN_LOG_FILE = LOG_DIR / 'application.log'
ERROR_LOG_FILE = LOG_DIR / 'error.log'
ACCESS_LOG_FILE = LOG_DIR / 'access.log'
DEBUG_LOG_FILE = LOG_DIR / 'debug.log'

# Define log format
DETAILED_FORMAT = logging.Formatter(
    fmt='%(asctime)s - %(name)s - %(levelname)s - [%(filename)s:%(lineno)d] - %(funcName)s() - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

SIMPLE_FORMAT = logging.Formatter(
    fmt='%(asctime)s - %(levelname)s - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

JSON_FORMAT = logging.Formatter(
    fmt='{"timestamp": "%(asctime)s", "level": "%(levelname)s", "logger": "%(name)s", "message": "%(message)s", "module": "%(module)s", "function": "%(funcName)s", "line": %(lineno)d}',
    datefmt='%Y-%m-%d %H:%M:%S'
)

# Configure root logger
root_logger = logging.getLogger()
root_logger.setLevel(logging.DEBUG)

# Remove existing handlers
for handler in root_logger.handlers[:]:
    root_logger.removeHandler(handler)

# Main application log handler (INFO and above)
main_handler = logging.handlers.RotatingFileHandler(
    filename=MAIN_LOG_FILE,
    maxBytes=50 * 1024 * 1024,  # 50 MB
    backupCount=10,
    encoding='utf-8'
)
main_handler.setLevel(logging.INFO)
main_handler.setFormatter(DETAILED_FORMAT)
root_logger.addHandler(main_handler)

# Error log handler (ERROR and above)
error_handler = logging.handlers.RotatingFileHandler(
    filename=ERROR_LOG_FILE,
    maxBytes=50 * 1024 * 1024,  # 50 MB
    backupCount=20,
    encoding='utf-8'
)
error_handler.setLevel(logging.ERROR)
error_handler.setFormatter(DETAILED_FORMAT)
root_logger.addHandler(error_handler)

# Debug log handler with time-based rotation
debug_handler = logging.handlers.TimedRotatingFileHandler(
    filename=DEBUG_LOG_FILE,
    when='midnight',
    interval=1,
    backupCount=7,
    encoding='utf-8'
)
debug_handler.setLevel(logging.DEBUG)
debug_handler.setFormatter(DETAILED_FORMAT)
debug_handler.suffix = '%Y-%m-%d'
