# Set file permissions
for log_file in [MAIN_LOG_FILE, ERROR_LOG_FILE, ACCESS_LOG_FILE, DEBUG_LOG_FILE, security_log_file, performance_log_file]:
    if log_file.exists():
        os.chmod(log_file, 0o640)

def get_logger(name=None):
    """Get a logger instance with the specified name"""
    return logging.getLogger(name) if name else logging.getLogger()

def log_exception(logger, exc_info=True):
    """Log exception with full traceback"""
    logger.exception("An exception occurred:", exc_info=exc_info)

